// pl_chf: leere Summe (keine Transactions) → null setzen
rows = rows.map(function(r) {
    if (r.num_exits === 0) r.pl_chf = null;
    return r;
});
msg.payload = JSON.stringify(rows);
msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*'
};
return msg;

