// Activities mit zugehörigem P/L (Timestamp-Match ±2 Sekunden)
msg.topic = "SELECT " +
  "a.date_utc, " +
  "a.direction, " +
  "a.level, " +
  "a.open_price, " +
  "a.source, " +
  "a.size, " +
  "(SELECT t.pl_chf FROM transactions t " +
  " WHERE t.deal_id = a.deal_id " +
  " AND ABS(strftime('%s', t.date_utc) - strftime('%s', a.date_utc)) <= 2 " +
  " LIMIT 1) AS pl_chf " +
  "FROM activities a " +
  "WHERE a.deal_id = '" + dealId + "' " +
  "ORDER BY a.date_utc ASC";
msg.payload = [];
return msg;

msg.payload = JSON.stringify(msg.payload || []);
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' };
return msg;

var body   = msg.payload || {};
var dealId = (body.dealId || '').replace(/'/g, "''");
var quelle = (body.quelle || '').replace(/'/g, "''");
var notiz  = (body.notiz  || '').replace(/'/g, "''");
var now    = new Date().toISOString();

if (!dealId) {
    msg.payload = JSON.stringify({ error: 'dealId fehlt' });
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' };
    node.send([null, msg]);
    return null;
}

msg.topic = "INSERT OR REPLACE INTO trade_tags (deal_id, quelle, notiz, tagged_at) VALUES (" +
  "'" + dealId + "', " +
  (quelle ? "'" + quelle + "'" : 'NULL') + ", " +
  (notiz  ? "'" + notiz  + "'" : 'NULL') + ", " +
  "'" + now + "')";
msg.payload = [];
return msg;

msg.payload = JSON.stringify({ ok: true });
