msg.topic = "SELECT key, value FROM config";
msg.payload = [];
return msg;

var rows = msg.payload || [];
var cfg  = {};
rows.forEach(function(r) { cfg[r.key] = r.value; });
msg.payload = JSON.stringify(cfg);
msg.statusCode = 200;
